import { describe, expect, it } from 'vitest';

import { buleyCostAlgebra, natCostAlgebra } from '../src/cost-algebra';
import {
  CostAlgebraViolation,
  requireBuleHotReplicaAdmission,
  requireCostHom,
  requireHotReplicaAdmission,
  requireOperationalPillars,
  requirePillarFuture,
  requirePillarPast,
  requirePillarPresent,
  requireThreePillars,
} from '../src/cost-algebra-enforcement';
import {
  TOWER_CEILINGS,
  vacuumBuleyProjection,
  type BuleyProjection,
} from '../src/spectral-noise-monitor';

describe('Hot-Replica admission enforcement', () => {
  it('admits an in-budget request without throwing', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    expect(() => requireBuleHotReplicaAdmission(b, 2, 12)).not.toThrow();
  });

  it('throws CostAlgebraViolation on over-budget request', () => {
    const b: BuleyProjection = { waste: 18, opportunity: 0, diversity: 0, score: 18 };
    try {
      requireBuleHotReplicaAdmission(b, 2, TOWER_CEILINGS.hexon);
      expect.fail('expected throw');
    } catch (e) {
      expect(e).toBeInstanceOf(CostAlgebraViolation);
      expect((e as CostAlgebraViolation).gate).toBe('hot-replica-admission');
      expect((e as CostAlgebraViolation).message).toContain('exceeds ceiling');
    }
  });

  it('vacuum is always admissible — no throw on any k', () => {
    for (const k of [1, 2, 100]) {
      expect(() => requireBuleHotReplicaAdmission(vacuumBuleyProjection, k, 0)).not.toThrow();
    }
  });

  it('generic requireHotReplicaAdmission works on natCostAlgebra', () => {
    expect(() => requireHotReplicaAdmission(natCostAlgebra, 5, 2, 10)).not.toThrow();
    expect(() => requireHotReplicaAdmission(natCostAlgebra, 5, 3, 10)).toThrow(
      CostAlgebraViolation,
    );
  });
});

describe('CostHom enforcement', () => {
  it('accepts a valid score-preserving hom (scoreHom-style)', () => {
    const witnesses: BuleyProjection[] = [
      vacuumBuleyProjection,
      { waste: 1, opportunity: 0, diversity: 0, score: 1 },
      { waste: 2, opportunity: 3, diversity: 1, score: 6 },
    ];
    expect(() =>
      requireCostHom((b) => b.score, buleyCostAlgebra, natCostAlgebra, witnesses),
    ).not.toThrow();
  });

  it('rejects a fst-projection that drops score', () => {
    const witnesses: BuleyProjection[] = [
      vacuumBuleyProjection,
      { waste: 2, opportunity: 3, diversity: 1, score: 6 },
    ];
    try {
      requireCostHom((b) => b.waste, buleyCostAlgebra, natCostAlgebra, witnesses);
      expect.fail('expected throw');
    } catch (e) {
      expect(e).toBeInstanceOf(CostAlgebraViolation);
      expect((e as CostAlgebraViolation).gate).toBe('cost-hom');
      expect((e as CostAlgebraViolation).message).toContain('preserve_score');
    }
  });
});

describe('Pillar enforcement', () => {
  const inHexon: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
  const overHexon: BuleyProjection = { waste: 18, opportunity: 0, diversity: 0, score: 18 };

  it('past pillar always passes for reachable states', () => {
    expect(() => requirePillarPast(vacuumBuleyProjection)).not.toThrow();
    expect(() => requirePillarPast(inHexon)).not.toThrow();
    expect(() => requirePillarPast(overHexon)).not.toThrow();
  });

  it('present pillar passes inside the manifold, throws outside', () => {
    expect(() => requirePillarPresent(inHexon)).not.toThrow();
    expect(() => requirePillarPresent(overHexon)).toThrow(CostAlgebraViolation);
  });

  it('present pillar respects custom ceiling', () => {
    expect(() => requirePillarPresent(inHexon, TOWER_CEILINGS.triton)).toThrow(
      CostAlgebraViolation,
    );
  });

  it('future pillar passes only at the vacuum', () => {
    expect(() => requirePillarFuture(vacuumBuleyProjection)).not.toThrow();
    expect(() => requirePillarFuture(inHexon)).toThrow(CostAlgebraViolation);
  });

  it('three-pillar gate fails on present + future for over-Hexon state', () => {
    try {
      requireThreePillars(overHexon);
      expect.fail('expected throw');
    } catch (e) {
      expect(e).toBeInstanceOf(CostAlgebraViolation);
      expect((e as CostAlgebraViolation).gate).toBe('three-pillar');
      expect((e as CostAlgebraViolation).message).toContain('present');
      expect((e as CostAlgebraViolation).message).toContain('future');
    }
  });

  it('three-pillar gate passes only on the vacuum', () => {
    expect(() => requireThreePillars(vacuumBuleyProjection)).not.toThrow();
    expect(() => requireThreePillars(inHexon)).toThrow(CostAlgebraViolation);
  });

  it('operational gate accepts inside-Hexon state (future-pillar tolerated)', () => {
    expect(() => requireOperationalPillars(inHexon)).not.toThrow();
    const report = requireOperationalPillars(inHexon);
    expect(report.past.anchored).toBe(true);
    expect(report.present.insideManifold).toBe(true);
    expect(report.future.freeDuplication).toBe(false); // reported, not enforced
  });

  it('operational gate rejects over-Hexon state (present-pillar fails)', () => {
    expect(() => requireOperationalPillars(overHexon)).toThrow(CostAlgebraViolation);
  });
});
